#include <sqlgen/sqlite.hpp>

namespace test_create_eas_database {
  void create_eas_database() {
    // Create the data directory if it doesn't exist
    std::filesystem::create_directories("data");

    // Create the EAS database file by connecting to it
    auto eas_conn = sqlgen::sqlite::connect("data/eas_database.db").value();

    // Connect to the main test database
    auto main_conn = sqlgen::sqlite::connect("test_db.sqlite").value();

    // Execute the ATTACH statement to attach the EAS database
    main_conn->execute("ATTACH DATABASE 'data/eas_database.db' AS EAS_DB;");
  }
}
```

