```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // Start transaction
  auto transaction_result = sqlgen::begin_transaction(conn);
  if (!transaction_result) {
    return false;
  }

  try {
    // Read from_account balance
    auto from_account_result = (sqlgen::read<std::vector<Account>> 
                               | sqlgen::where("account_id"_c == from_account_id))(conn);

    if (!from_account_result) {
      sqlgen::rollback(conn);
      return false;
    }

    auto from_account = from_account_result.value();
    if (from_account.empty()) {
      sqlgen::rollback(conn);
      return false;
    }

    auto from_balance = from_account[0].balance;

    // Check sufficient funds
    if (from_balance < amount) {
      sqlgen::rollback(conn);
      return false;
    }

    // Update from_account: balance = balance - amount
    auto update_from_result = (sqlgen::update<Account>("balance"_c.set("balance"_c - amount)) 
                             | sqlgen::where("account_id"_c == from_account_id))(conn);

    if (!update_from_result) {
      sqlgen::rollback(conn);
      return false;
    }

    // Update to_account: balance = balance + amount
