std::string generate_sql_dry_run() {
  using namespace sqlgen::literals;

  // Define the join condition: B.a_id = A.id
  auto join_condition = "a_id"_t1 == "id"_t2;

  // Define the where condition: B.score > 10 AND A.name LIKE '%x%'
  auto where_condition = ("score"_t1 > 10) && ("name"_t2.like("%x%"));

  // Build the query using sqlgen's fluent interface
  auto query = sqlgen::read<std::vector<B>>  // Start from table B
               | sqlgen::join<A, "a">(join_condition)  // Join with table A
               | sqlgen::where(where_condition)        // Apply where conditions
               | sqlgen::order_by("score"_t1.desc())   // Order by B.score descending
               | sqlgen::limit(5);                     // Limit to 5 results

  // Generate the SQL string for SQLite
  return sqlgen::sqlite::to_sql(query);
}

}  // namespace generate_sql_dry_run
```

