namespace mathematical_operations_analysis {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int quantity;
  double discount_rate;
};

struct MathAnalysis {
  int product_id;
  std::string name;
  double abs_price;
  double ceil_price;
