namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false; // Connection failed
  }
  auto conn = *conn_result;

  // 2. Drop tables if they exist (clean up)
  auto drop_parent = sqlgen::drop<Parent> | sqlgen::if_exists;
  auto drop_child = sqlgen::drop<Child> | sqlgen::if_exists;
  drop_parent(conn);
  drop_child(conn);

  // 3. Create tables
  sqlgen::create_table<Parent>(conn);
  sqlgen::create_table<Child>(conn);

  // 4. Insert test data
  std::vector<Parent> parents{ {1, "Parent1"}, {2, "Parent2"} };
  std::vector<Child> children{ {1, 1, "Child of Parent1"}, {2, 2, "Child of Parent2"} };

  // Insert parents
  auto insert_parent_result = conn.insert(parents.begin(), parents.end());
  if (!insert_parent_result) {
    return false; // Insert failed
  }

  // Insert children  
  auto insert_child_result = conn.insert(children.begin(), children.end());
  if (!insert_child_result) {
    return false; // Insert failed
  }

  // 5. Delete parent and verify cascade deletion
  // Delete parent with ID=1
  auto delete_result = conn.execute("DELETE FROM Parent WHERE parent_id = 1");
  if (!delete_result) {
