  auto update_stmt2 = sqlgen::update<Account>(
      "balance"_c.set(2000.0),
      "status"_c.set("inactive")
  ) | sqlgen::where("account_id"_c == 2);

  auto update_result2 = update_stmt2(conn);
  if (!update_result2) {
    return false;
  }

  // 5. Verify the changes by reading the data back
